module sd_card_interface(  
    input wire CLK,  
    input wire RESET,  
    input wire CMD,  
    input wire [7:0] DATA_IN,  
    output reg [7:0] DATA_OUT,  
    output reg READY  
);  
    reg [7:0] external_buffer;  
    reg state; // 0 = reading, 1 = writing  

    always @(posedge CLK or posedge RESET) begin  
        if (RESET) begin  
            external_buffer <= 8'b0;  
            DATA_OUT <= 8'b0;  
            READY <= 1;  
            state <= 0;  
        end else begin  
            if (CMD) begin // Write command  
                external_buffer <= DATA_IN;  
                READY <= 1;  
                state <= 1;  
            end else begin // Read command  
                DATA_OUT <= external_buffer;  
                READY <= 1;  
                state <= 0;  
            end  
        end  
    end  
endmodule
